import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        chicken = (Z % X == 0)
        duck = (Z % Y == 0)
        if chicken and duck:
            out.append('ANY')
        elif chicken:
            out.append('CHICKEN')
        elif duck:
            out.append('DUCK')
        else:
            out.append('NONE')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

